import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import { BiometricAuth } from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    checkBiometry();
  }, []);

  const checkBiometry = async () => {
    try {
      const biometricAuth = new BiometricAuth({
        promptMessage: 'Please authenticate',
        canBeFalse: true,
      });
      const isEnrolled = await biometricAuth.isEnrolled();
      if (isEnrolled) {
        const result = await biometricAuth.authenticate();
        if (result.success) {
          setIsAuthenticated(true);
          storeAuthenticationStatus(true);
        } else {
          Alert.alert('Error', 'Biometric authentication failed');
        }
      } else {
        Alert.alert('Error', 'No biometric data available');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const storeAuthenticationStatus = async (status) => {
    try {
      await AsyncStorage.setItem('isAuthenticated', status.toString());
    } catch (error) {
      console.error(error);
    }
  };

  const loginScreen = () => {
    if (!isAuthenticated) {
      return (
        <View>
          <Text>Login Screen</Text>
          <Button title="Login" onPress={checkBiometry} />
        </View>
      );
    } else {
      return null;
    }
  };

  return (
    <View>
      {loginScreen()}
      <Button
        title="Skip Login"
        onPress={() => storeAuthenticationStatus(true)}
      />
    </View>
  );
};

export default App;